package main;

import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;

public class CopasGameState {
    public static final int HUMAN_PLAYER_INDEX = 0;
    private static final String[] DEFAULT_PLAYER_NAMES = {"You", "AI 1", "AI 2", "AI 3"};
    private static final int STARTING_HAND_SIZE = 4;
    private static final String[] SUITS = {"Basto", "Copa", "Espada", "Oro"};

    public record AiTurnResult(int playerIndex, Card cardPlayed, boolean roundOver) {}
    public enum ActionType { PLAY_CARD, DRAW_CARD }
    public record ActionEvent(ActionType type, int actorPlayerIndex, Card card,
                              int affectedPlayerIndex, int affectedCardCount) {}
    public record PlayerActionResult(boolean success, ActionEvent event, String errorMessage) {}

    private final int playerCount;
    private final String[] playerNames;
    private final boolean[] finishedPlayers;

    private Deck drawPile;
    private final List<Card> discardPile = new ArrayList<>();
    private final List<List<Card>> playerHands = new ArrayList<>();

    private int currentPlayerIndex = HUMAN_PLAYER_INDEX;
    private String activeSuit;
    private String statusMessage = "Your turn. Play a matching card or draw from the pile.";
    private boolean roundOver;
    private boolean humanHasDrawnThisTurn;

    public CopasGameState() {
        this(DEFAULT_PLAYER_NAMES);
    }

    public CopasGameState(String[] playerNames) {
        if (playerNames == null || playerNames.length < 2) {
            throw new IllegalArgumentException("At least two players are required.");
        }

        this.playerNames = playerNames.clone();
        this.playerCount = playerNames.length;
        this.finishedPlayers = new boolean[playerCount];
        startRound();
    }

    public void startRound() {
        drawPile = Deck.createShuffledSpanishDeck();
        discardPile.clear();
        playerHands.clear();
        roundOver = false;
        humanHasDrawnThisTurn = false;
        currentPlayerIndex = HUMAN_PLAYER_INDEX;

        for (int playerIndex = 0; playerIndex < playerCount; playerIndex++) {
            finishedPlayers[playerIndex] = false;
            playerHands.add(drawPile.dealCards(STARTING_HAND_SIZE));
        }

        Card openingCard = drawFromPile();
        if (openingCard == null) {
            throw new IllegalStateException("Unable to start the round because no opening card could be drawn.");
        }

        discardPile.add(openingCard);
        activeSuit = openingCard.getType();
        statusMessage = getPlayerName(HUMAN_PLAYER_INDEX) + " turn. Top card: "
                + openingCard.getDisplayName() + ". Active suit: " + activeSuit + ".";
    }

    public List<Card> getHumanHand() {
        return getPlayerHand(HUMAN_PLAYER_INDEX);
    }

    public List<Card> getPlayerHand(int playerIndex) {
        validatePlayerIndex(playerIndex);
        return List.copyOf(playerHands.get(playerIndex));
    }

    public Card getTopCard() {
        return discardPile.getLast();
    }

    public String getActiveSuit() {
        return activeSuit;
    }

    public String getStatusMessage() {
        return statusMessage;
    }

    public int getDrawPileSize() {
        return drawPile.size();
    }

    public int getPlayerCount() {
        return playerCount;
    }

    public boolean isHumanTurn() {
        return isPlayerTurn(HUMAN_PLAYER_INDEX);
    }

    public boolean isAiTurn() {
        return !roundOver && currentPlayerIndex != HUMAN_PLAYER_INDEX;
    }

    public boolean isPlayerTurn(int playerIndex) {
        validatePlayerIndex(playerIndex);
        return !roundOver && currentPlayerIndex == playerIndex && !finishedPlayers[playerIndex];
    }

    public boolean isHumanCardPlayable(int handIndex) {
        return isPlayerCardPlayable(HUMAN_PLAYER_INDEX, handIndex);
    }

    public boolean isPlayerCardPlayable(int playerIndex, int handIndex) {
        validatePlayerIndex(playerIndex);
        List<Card> hand = playerHands.get(playerIndex);
        if (handIndex < 0 || handIndex >= hand.size()) {
            return false;
        }

        return canPlay(hand.get(handIndex));
    }

    public boolean canHumanDraw() {
        return canPlayerDraw(HUMAN_PLAYER_INDEX);
    }

    public boolean canPlayerDraw(int playerIndex) {
        validatePlayerIndex(playerIndex);
        if (!isPlayerTurn(playerIndex) || !canDrawFromPile()) {
            return false;
        }

        if (playerIndex == HUMAN_PLAYER_INDEX) {
            return !humanHasDrawnThisTurn && !hasPlayableCard(playerIndex);
        }

        return !hasPlayableCard(playerIndex);
    }

    public boolean isRoundOver() {
        return roundOver;
    }

    public boolean hasAvailableDrawPile() {
        return canDrawFromPile();
    }

    public int getCurrentPlayerIndex() {
        return currentPlayerIndex;
    }

    public int getPlayerCardCount(int playerIndex) {
        validatePlayerIndex(playerIndex);
        return playerHands.get(playerIndex).size();
    }

    public String getPlayerName(int playerIndex) {
        validatePlayerIndex(playerIndex);
        return playerNames[playerIndex];
    }

    public boolean isPlayerFinished(int playerIndex) {
        validatePlayerIndex(playerIndex);
        return finishedPlayers[playerIndex];
    }

    public boolean playHumanCard(int handIndex, String chosenSuit) {
        return playCardForPlayer(HUMAN_PLAYER_INDEX, handIndex, chosenSuit).success();
    }

    public PlayerActionResult playCardForPlayer(int playerIndex, int handIndex, String chosenSuit) {
        validatePlayerIndex(playerIndex);
        if (!isPlayerTurn(playerIndex)) {
            String message = roundOver ? statusMessage : "Wait for your turn.";
            statusMessage = message;
            return new PlayerActionResult(false, null, message);
        }

        List<Card> hand = playerHands.get(playerIndex);
        if (handIndex < 0 || handIndex >= hand.size()) {
            statusMessage = "That card is no longer available.";
            return new PlayerActionResult(false, null, statusMessage);
        }

        Card card = hand.get(handIndex);
        if (!canPlay(card)) {
            statusMessage = "You can only play a card with the same number or the active suit (" + activeSuit + ").";
            return new PlayerActionResult(false, null, statusMessage);
        }

        PlayedCardResult result = playCard(playerIndex, handIndex, normalizeChosenSuit(card, chosenSuit));
        return new PlayerActionResult(
                true,
                new ActionEvent(ActionType.PLAY_CARD, playerIndex, result.card(), result.affectedPlayerIndex(), result.affectedCardCount()),
                null
        );
    }

    public void drawForHuman() {
        drawForPlayer(HUMAN_PLAYER_INDEX);
    }

    public PlayerActionResult drawForPlayer(int playerIndex) {
        validatePlayerIndex(playerIndex);
        if (!isPlayerTurn(playerIndex)) {
            String message = roundOver ? statusMessage : "Wait for your turn before drawing.";
            statusMessage = message;
            return new PlayerActionResult(false, null, message);
        }
        if (playerIndex == HUMAN_PLAYER_INDEX && humanHasDrawnThisTurn) {
            statusMessage = "You already drew this turn. Play a valid card if you can.";
            return new PlayerActionResult(false, null, statusMessage);
        }
        if (hasPlayableCard(playerIndex)) {
            statusMessage = "You already have a playable card. Play it instead of drawing.";
            return new PlayerActionResult(false, null, statusMessage);
        }

        Card drawnCard = drawFromPile();
        if (drawnCard == null) {
            statusMessage = "No cards left to draw.";
            return new PlayerActionResult(false, null, statusMessage);
        }

        playerHands.get(playerIndex).add(drawnCard);
        if (playerIndex == HUMAN_PLAYER_INDEX) {
            humanHasDrawnThisTurn = true;
        }

        if (canPlay(drawnCard)) {
            statusMessage = getPlayerName(playerIndex) + " drew " + drawnCard.getDisplayName()
                    + " and may play it or another valid card.";
        } else {
            statusMessage = getPlayerName(playerIndex) + " drew " + drawnCard.getDisplayName() + " and passed.";
            currentPlayerIndex = getNextActivePlayer(playerIndex);
            if (!roundOver && currentPlayerIndex == HUMAN_PLAYER_INDEX) {
                humanHasDrawnThisTurn = false;
            }
        }

        return new PlayerActionResult(
                true,
                new ActionEvent(ActionType.DRAW_CARD, playerIndex, drawnCard, playerIndex, 1),
                null
        );
    }

    /** Executes exactly one AI player's turn and returns what happened. GamePanel calls this
     *  after its delay timer fires so each AI move is shown with a delay and animation. */
    public AiTurnResult stepAiTurn() {
        if (!isAiTurn()) return null;

        int aiIndex = currentPlayerIndex;

        if (finishedPlayers[aiIndex]) {
            currentPlayerIndex = getNextActivePlayer(aiIndex);
            if (!roundOver && currentPlayerIndex == HUMAN_PLAYER_INDEX) humanHasDrawnThisTurn = false;
            return new AiTurnResult(aiIndex, null, roundOver);
        }

        List<Card> aiHand = playerHands.get(aiIndex);
        int playableIndex = findPlayableCardIndex(aiHand);
        Card cardPlayed = null;

        if (playableIndex >= 0) {
            Card card = aiHand.get(playableIndex);
            String chosenSuit = card.isSuitChange() ? chooseSuitForAi(aiHand, playableIndex) : null;
            cardPlayed = card;
            playCard(aiIndex, playableIndex, chosenSuit);
        } else {
            Card drawnCard = drawFromPile();
            if (drawnCard != null) {
                aiHand.add(drawnCard);
                if (canPlay(drawnCard)) {
                    String chosenSuit = drawnCard.isSuitChange() ? chooseSuitForAi(aiHand, aiHand.size() - 1) : null;
                    cardPlayed = drawnCard;
                    playCard(aiIndex, aiHand.size() - 1, chosenSuit);
                } else {
                    statusMessage = getPlayerName(aiIndex) + " drew a card and passed.";
                    currentPlayerIndex = getNextActivePlayer(aiIndex);
                }
            } else {
                statusMessage = getPlayerName(aiIndex) + " could not draw.";
                currentPlayerIndex = getNextActivePlayer(aiIndex);
            }
        }

        if (!roundOver && currentPlayerIndex == HUMAN_PLAYER_INDEX) humanHasDrawnThisTurn = false;
        return new AiTurnResult(aiIndex, cardPlayed, roundOver);
    }

    private PlayedCardResult playCard(int playerIndex, int handIndex, String chosenSuit) {
        List<Card> hand = playerHands.get(playerIndex);
        Card card = hand.remove(handIndex);
        discardPile.add(card);
        activeSuit = card.isSuitChange() ? chosenSuit : card.getType();

        StringBuilder actionMessage = new StringBuilder();
        actionMessage.append(getPlayerName(playerIndex))
                .append(" played ")
                .append(card.getDisplayName());

        if (card.isSuitChange()) {
            actionMessage.append(" and changed the suit to ").append(activeSuit);
        }

        if (hand.isEmpty()) {
            markPlayerFinished(playerIndex, actionMessage);
        }

        CardEffectResult effect = applyCardEffect(playerIndex, card, actionMessage);

        if (!roundOver) {
            statusMessage = actionMessage.append('.').toString();
        }

        return new PlayedCardResult(card, effect.affectedPlayerIndex(), effect.affectedCardCount());
    }

    private CardEffectResult applyCardEffect(int playerIndex, Card card, StringBuilder actionMessage) {
        if (remainingPlayers() <= 1) {
            finishRound();
            return new CardEffectResult(-1, 0);
        }

        if (card.isGoldenOne()) {
            int targetPlayer = getNextActivePlayer(playerIndex);
            int drawn = drawCardsForPlayer(targetPlayer, 5);
            actionMessage.append(". ").append(getPlayerName(targetPlayer)).append(" draws ").append(drawn).append(" cards and is skipped");
            currentPlayerIndex = getNextActivePlayer(targetPlayer);
            return new CardEffectResult(targetPlayer, drawn);
        }

        if (card.isDrawTwo()) {
            int targetPlayer = getNextActivePlayer(playerIndex);
            int drawn = drawCardsForPlayer(targetPlayer, 2);
            actionMessage.append(". ").append(getPlayerName(targetPlayer)).append(" draws ").append(drawn).append(" cards and is skipped");
            currentPlayerIndex = getNextActivePlayer(targetPlayer);
            return new CardEffectResult(targetPlayer, drawn);
        }

        if (card.isSkip()) {
            int skippedPlayer = getNextActivePlayer(playerIndex);
            actionMessage.append(". ").append(getPlayerName(skippedPlayer)).append(" is skipped");
            currentPlayerIndex = getNextActivePlayer(skippedPlayer);
            return new CardEffectResult(skippedPlayer, 0);
        }

        currentPlayerIndex = getNextActivePlayer(playerIndex);
        return new CardEffectResult(-1, 0);
    }

    private void markPlayerFinished(int playerIndex, StringBuilder actionMessage) {
        if (finishedPlayers[playerIndex]) {
            return;
        }

        finishedPlayers[playerIndex] = true;
        actionMessage.append(" and finished their cards");
    }

    private void finishRound() {
        roundOver = true;
        int loserIndex = -1;

        for (int playerIndex = 0; playerIndex < playerCount; playerIndex++) {
            if (!finishedPlayers[playerIndex]) {
                loserIndex = playerIndex;
                break;
            }
        }

        if (loserIndex == HUMAN_PLAYER_INDEX) {
            statusMessage = "Round over. You are the last player with cards and lose this round.";
        } else if (loserIndex >= 0) {
            statusMessage = "Round over. " + getPlayerName(loserIndex) + " is the last player with cards and loses this round.";
        } else {
            statusMessage = "Round over.";
        }
    }

    private int drawCardsForPlayer(int playerIndex, int count) {
        int drawnCards = 0;

        for (int i = 0; i < count; i++) {
            Card card = drawFromPile();
            if (card == null) {
                break;
            }
            playerHands.get(playerIndex).add(card);
            drawnCards++;
        }

        return drawnCards;
    }

    private Card drawFromPile() {
        replenishDrawPileIfNeeded();
        if (drawPile.isEmpty()) {
            return null;
        }

        return drawPile.drawCard();
    }

    private boolean canDrawFromPile() {
        return !drawPile.isEmpty() || discardPile.size() > 1;
    }

    private void replenishDrawPileIfNeeded() {
        if (!drawPile.isEmpty() || discardPile.size() <= 1) {
            return;
        }

        Card topCard = discardPile.removeLast();
        List<Card> recycledCards = new ArrayList<>(discardPile);
        discardPile.clear();
        discardPile.add(topCard);

        drawPile = new Deck(recycledCards);
        drawPile.shuffle();
    }

    private boolean canPlay(Card card) {
        return card.matches(getTopCard(), activeSuit);
    }

    private boolean hasPlayableCard(int playerIndex) {
        return playerHands.get(playerIndex).stream().anyMatch(this::canPlay);
    }

    private int findPlayableCardIndex(List<Card> hand) {
        for (int cardIndex = 0; cardIndex < hand.size(); cardIndex++) {
            if (canPlay(hand.get(cardIndex))) {
                return cardIndex;
            }
        }
        return -1;
    }

    private int getNextActivePlayer(int fromPlayerIndex) {
        int nextPlayerIndex = fromPlayerIndex;
        do {
            nextPlayerIndex = (nextPlayerIndex + 1) % playerCount;
        } while (finishedPlayers[nextPlayerIndex]);
        return nextPlayerIndex;
    }

    private int remainingPlayers() {
        int count = 0;
        for (boolean finished : finishedPlayers) {
            if (!finished) {
                count++;
            }
        }
        return count;
    }

    private String chooseSuitForAi(List<Card> hand, int playedCardIndex) {
        List<Card> remainingCards = new ArrayList<>(hand);
        remainingCards.remove(playedCardIndex);

        return remainingCards.stream()
                .filter(card -> !card.isSuitChange())
                .collect(java.util.stream.Collectors.groupingBy(Card::getType, java.util.stream.Collectors.counting()))
                .entrySet()
                .stream()
                .max(Comparator.comparingLong(java.util.Map.Entry::getValue))
                .map(java.util.Map.Entry::getKey)
                .orElse(SUITS[0]);
    }

    private String normalizeChosenSuit(Card card, String chosenSuit) {
        if (!card.isSuitChange()) {
            return card.getType();
        }

        for (String suit : SUITS) {
            if (suit.equals(chosenSuit)) {
                return suit;
            }
        }

        return card.getType();
    }

    private void validatePlayerIndex(int playerIndex) {
        if (playerIndex < 0 || playerIndex >= playerCount) {
            throw new IllegalArgumentException("Unknown player index: " + playerIndex);
        }
    }

    private record CardEffectResult(int affectedPlayerIndex, int affectedCardCount) {}
    private record PlayedCardResult(Card card, int affectedPlayerIndex, int affectedCardCount) {}
}

package main;

import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;

public class CopasGameState {
    public static final int HUMAN_PLAYER_INDEX = 0;
    private static final String[] DEFAULT_PLAYER_NAMES = {"You", "AI 1", "AI 2", "AI 3"};
    private static final int STARTING_HAND_SIZE = 4;
    private static final String[] SUITS = {"Basto", "Copa", "Espada", "Oro"};

    public record AiTurnResult(int playerIndex, Card cardPlayed, boolean roundOver) {}
    public enum ActionType { PLAY_CARD, DRAW_CARD }
    public record ActionEvent(ActionType type, int actorPlayerIndex, Card card,
                              int affectedPlayerIndex, int affectedCardCount) {}
    public record PlayerActionResult(boolean success, ActionEvent event, String errorMessage) {}

    private final int playerCount;
    private final String[] playerNames;
    private final boolean[] finishedPlayers;

    private Deck drawPile;
    private final List<Card> discardPile = new ArrayList<>();
    private final List<List<Card>> playerHands = new ArrayList<>();

    private int currentPlayerIndex = HUMAN_PLAYER_INDEX;
    private String activeSuit;
    private String statusMessage = "Your turn. Play a matching card or draw from the pile.";
    private boolean roundOver;
    private boolean humanHasDrawnThisTurn;

    public CopasGameState() {
        this(DEFAULT_PLAYER_NAMES);
    }

    public CopasGameState(String[] playerNames) {
        if (playerNames == null || playerNames.length < 2) {
            throw new IllegalArgumentException("At least two players are required.");
        }

        this.playerNames = playerNames.clone();
        this.playerCount = playerNames.length;
        this.finishedPlayers = new boolean[playerCount];
        startRound();
    }

    public void startRound() {
        drawPile = Deck.createShuffledSpanishDeck();
        discardPile.clear();
        playerHands.clear();
        roundOver = false;
        humanHasDrawnThisTurn = false;
        currentPlayerIndex = HUMAN_PLAYER_INDEX;

        for (int playerIndex = 0; playerIndex < playerCount; playerIndex++) {
            finishedPlayers[playerIndex] = false;
            playerHands.add(drawPile.dealCards(STARTING_HAND_SIZE));
        }

        Card openingCard = drawFromPile();
        if (openingCard == null) {
            throw new IllegalStateException("Unable to start the round because no opening card could be drawn.");
        }

        discardPile.add(openingCard);
        activeSuit = openingCard.getType();
        statusMessage = getPlayerName(HUMAN_PLAYER_INDEX) + " turn. Top card: "
                + openingCard.getDisplayName() + ". Active suit: " + activeSuit + ".";
    }

    public List<Card> getHumanHand() {
        return getPlayerHand(HUMAN_PLAYER_INDEX);
    }

    public List<Card> getPlayerHand(int playerIndex) {
        validatePlayerIndex(playerIndex);
        return List.copyOf(playerHands.get(playerIndex));
    }

    public Card getTopCard() {
        return discardPile.getLast();
    }

    public String getActiveSuit() {
        return activeSuit;
    }

    public String getStatusMessage() {
        return statusMessage;
    }

    public int getDrawPileSize() {
        return drawPile.size();
    }

    public int getPlayerCount() {
        return playerCount;
    }

    public boolean isHumanTurn() {
        return isPlayerTurn(HUMAN_PLAYER_INDEX);
    }

    public boolean isAiTurn() {
        return !roundOver && currentPlayerIndex != HUMAN_PLAYER_INDEX;
    }

    public boolean isPlayerTurn(int playerIndex) {
        validatePlayerIndex(playerIndex);
        return !roundOver && currentPlayerIndex == playerIndex && !finishedPlayers[playerIndex];
    }

    public boolean isHumanCardPlayable(int handIndex) {
        return isPlayerCardPlayable(HUMAN_PLAYER_INDEX, handIndex);
    }

    public boolean isPlayerCardPlayable(int playerIndex, int handIndex) {
        validatePlayerIndex(playerIndex);
        List<Card> hand = playerHands.get(playerIndex);
        if (handIndex < 0 || handIndex >= hand.size()) {
            return false;
        }

        return canPlay(hand.get(handIndex));
    }

    public boolean canHumanDraw() {
        return canPlayerDraw(HUMAN_PLAYER_INDEX);
    }

    public boolean canPlayerDraw(int playerIndex) {
        validatePlayerIndex(playerIndex);
        return isPlayerTurn(playerIndex) && canDrawFromPile();
    }

    public boolean isRoundOver() {
        return roundOver;
    }

    public boolean hasAvailableDrawPile() {
        return canDrawFromPile();
    }

    public int getCurrentPlayerIndex() {
        return currentPlayerIndex;
    }

    public int getPlayerCardCount(int playerIndex) {
        validatePlayerIndex(playerIndex);
        return playerHands.get(playerIndex).size();
    }

    public String getPlayerName(int playerIndex) {
        validatePlayerIndex(playerIndex);
        return playerNames[playerIndex];
    }

    public boolean isPlayerFinished(int playerIndex) {
        validatePlayerIndex(playerIndex);
        return finishedPlayers[playerIndex];
    }

    public boolean playHumanCard(int handIndex, String chosenSuit) {
        return playCardForPlayer(HUMAN_PLAYER_INDEX, handIndex, chosenSuit).success();
    }

    public PlayerActionResult playCardForPlayer(int playerIndex, int handIndex, String chosenSuit) {
        validatePlayerIndex(playerIndex);
        if (!isPlayerTurn(playerIndex)) {
            String message = roundOver ? statusMessage : "Wait for your turn.";
            statusMessage = message;
            return new PlayerActionResult(false, null, message);
        }

        List<Card> hand = playerHands.get(playerIndex);
        if (handIndex < 0 || handIndex >= hand.size()) {
            statusMessage = "That card is no longer available.";
            return new PlayerActionResult(false, null, statusMessage);
        }

        Card card = hand.get(handIndex);
        if (!canPlay(card)) {
            statusMessage = "You can only play a card with the same number or the active suit (" + activeSuit + ").";
            return new PlayerActionResult(false, null, statusMessage);
        }

        PlayedCardResult result = playCard(playerIndex, handIndex, normalizeChosenSuit(card, chosenSuit));
        return new PlayerActionResult(
                true,
                new ActionEvent(ActionType.PLAY_CARD, playerIndex, result.card(), result.affectedPlayerIndex(), result.affectedCardCount()),
                null
        );
    }

    public void drawForHuman() {
        drawForPlayer(HUMAN_PLAYER_INDEX);
    }

    public PlayerActionResult drawForPlayer(int playerIndex) {
        validatePlayerIndex(playerIndex);
        if (!isPlayerTurn(playerIndex)) {
            String message = roundOver ? statusMessage : "Wait for your turn before drawing.";
            statusMessage = message;
            return new PlayerActionResult(false, null, message);
        }

        Card drawnCard = drawFromPile();
        if (drawnCard == null) {
            statusMessage = "No cards left to draw.";
            return new PlayerActionResult(false, null, statusMessage);
        }

        playerHands.get(playerIndex).add(drawnCard);
        statusMessage = getPlayerName(playerIndex) + " drew " + drawnCard.getDisplayName() + " and passed.";
        currentPlayerIndex = getNextActivePlayer(playerIndex);
        if (!roundOver && currentPlayerIndex == HUMAN_PLAYER_INDEX) {
            humanHasDrawnThisTurn = false;
        }

        return new PlayerActionResult(
                true,
                new ActionEvent(ActionType.DRAW_CARD, playerIndex, drawnCard, playerIndex, 1),
                null
        );
    }

    /** Executes exactly one AI player's turn and returns what happened. GamePanel calls this
     *  after its delay timer fires so each AI move is shown with a delay and animation. */
    public AiTurnResult stepAiTurn() {
        if (!isAiTurn()) return null;

        int aiIndex = currentPlayerIndex;

        if (finishedPlayers[aiIndex]) {
            currentPlayerIndex = getNextActivePlayer(aiIndex);
            if (!roundOver && currentPlayerIndex == HUMAN_PLAYER_INDEX) humanHasDrawnThisTurn = false;
            return new AiTurnResult(aiIndex, null, roundOver);
        }

        List<Card> aiHand = playerHands.get(aiIndex);
        int playableIndex = findPlayableCardIndex(aiHand);
        Card cardPlayed = null;

        if (playableIndex >= 0) {
            Card card = aiHand.get(playableIndex);
            String chosenSuit = card.isSuitChange() ? chooseSuitForAi(aiHand, playableIndex) : null;
            cardPlayed = card;
            playCard(aiIndex, playableIndex, chosenSuit);
        } else {
            Card drawnCard = drawFromPile();
            if (drawnCard != null) {
                aiHand.add(drawnCard);
                statusMessage = getPlayerName(aiIndex) + " drew a card and passed.";
                currentPlayerIndex = getNextActivePlayer(aiIndex);
            } else {
                statusMessage = getPlayerName(aiIndex) + " could not draw.";
                currentPlayerIndex = getNextActivePlayer(aiIndex);
            }
        }

        if (!roundOver && currentPlayerIndex == HUMAN_PLAYER_INDEX) humanHasDrawnThisTurn = false;
        return new AiTurnResult(aiIndex, cardPlayed, roundOver);
    }

    private PlayedCardResult playCard(int playerIndex, int handIndex, String chosenSuit) {
        List<Card> hand = playerHands.get(playerIndex);
        Card card = hand.remove(handIndex);
        discardPile.add(card);
        activeSuit = card.isSuitChange() ? chosenSuit : card.getType();

        StringBuilder actionMessage = new StringBuilder();
        actionMessage.append(getPlayerName(playerIndex))
                .append(" played ")
                .append(card.getDisplayName());

        if (card.isSuitChange()) {
            actionMessage.append(" and changed the suit to ").append(activeSuit);
        }

        if (hand.isEmpty()) {
            markPlayerFinished(playerIndex, actionMessage);
        }

        CardEffectResult effect = applyCardEffect(playerIndex, card, actionMessage);

        if (!roundOver) {
            statusMessage = actionMessage.append('.').toString();
        }

        return new PlayedCardResult(card, effect.affectedPlayerIndex(), effect.affectedCardCount());
    }

    private CardEffectResult applyCardEffect(int playerIndex, Card card, StringBuilder actionMessage) {
        if (remainingPlayers() <= 1) {
            finishRound();
            return new CardEffectResult(-1, 0);
        }

        if (card.isGoldenOne()) {
            int targetPlayer = getNextActivePlayer(playerIndex);
            int drawn = drawCardsForPlayer(targetPlayer, 5);
            actionMessage.append(". ").append(getPlayerName(targetPlayer)).append(" draws ").append(drawn).append(" cards and is skipped");
            currentPlayerIndex = getNextActivePlayer(targetPlayer);
            return new CardEffectResult(targetPlayer, drawn);
        }

        if (card.isDrawTwo()) {
            int targetPlayer = getNextActivePlayer(playerIndex);
            int drawn = drawCardsForPlayer(targetPlayer, 2);
            actionMessage.append(". ").append(getPlayerName(targetPlayer)).append(" draws ").append(drawn).append(" cards and is skipped");
            currentPlayerIndex = getNextActivePlayer(targetPlayer);
            return new CardEffectResult(targetPlayer, drawn);
        }

        if (card.isSkip()) {
            int skippedPlayer = getNextActivePlayer(playerIndex);
            actionMessage.append(". ").append(getPlayerName(skippedPlayer)).append(" is skipped");
            currentPlayerIndex = getNextActivePlayer(skippedPlayer);
            return new CardEffectResult(skippedPlayer, 0);
        }

        currentPlayerIndex = getNextActivePlayer(playerIndex);
        return new CardEffectResult(-1, 0);
    }

    private void markPlayerFinished(int playerIndex, StringBuilder actionMessage) {
        if (finishedPlayers[playerIndex]) {
            return;
        }

        finishedPlayers[playerIndex] = true;
        actionMessage.append(" and finished their cards");
    }

    private void finishRound() {
        roundOver = true;
        int loserIndex = -1;

        for (int playerIndex = 0; playerIndex < playerCount; playerIndex++) {
            if (!finishedPlayers[playerIndex]) {
                loserIndex = playerIndex;
                break;
            }
        }

        if (loserIndex == HUMAN_PLAYER_INDEX) {
            statusMessage = "Round over. You are the last player with cards and lose this round.";
        } else if (loserIndex >= 0) {
            statusMessage = "Round over. " + getPlayerName(loserIndex) + " is the last player with cards and loses this round.";
        } else {
            statusMessage = "Round over.";
        }
    }

    private int drawCardsForPlayer(int playerIndex, int count) {
        int drawnCards = 0;

        for (int i = 0; i < count; i++) {
            Card card = drawFromPile();
            if (card == null) {
                break;
            }
            playerHands.get(playerIndex).add(card);
            drawnCards++;
        }

        return drawnCards;
    }

    private Card drawFromPile() {
        replenishDrawPileIfNeeded();
        if (drawPile.isEmpty()) {
            return null;
        }

        return drawPile.drawCard();
    }

    private boolean canDrawFromPile() {
        return !drawPile.isEmpty() || discardPile.size() > 1;
    }

    private void replenishDrawPileIfNeeded() {
        if (!drawPile.isEmpty() || discardPile.size() <= 1) {
            return;
        }

        Card topCard = discardPile.removeLast();
        List<Card> recycledCards = new ArrayList<>(discardPile);
        discardPile.clear();
        discardPile.add(topCard);

        drawPile = new Deck(recycledCards);
        drawPile.shuffle();
    }

    private boolean canPlay(Card card) {
        return card.matches(getTopCard(), activeSuit);
    }

    private boolean hasPlayableCard(int playerIndex) {
        return playerHands.get(playerIndex).stream().anyMatch(this::canPlay);
    }

    private int findPlayableCardIndex(List<Card> hand) {
        for (int cardIndex = 0; cardIndex < hand.size(); cardIndex++) {
            if (canPlay(hand.get(cardIndex))) {
                return cardIndex;
            }
        }
        return -1;
    }

    private int getNextActivePlayer(int fromPlayerIndex) {
        int nextPlayerIndex = fromPlayerIndex;
        do {
            nextPlayerIndex = (nextPlayerIndex + 1) % playerCount;
        } while (finishedPlayers[nextPlayerIndex]);
        return nextPlayerIndex;
    }

    private int remainingPlayers() {
        int count = 0;
        for (boolean finished : finishedPlayers) {
            if (!finished) {
                count++;
            }
        }
        return count;
    }

    private String chooseSuitForAi(List<Card> hand, int playedCardIndex) {
        List<Card> remainingCards = new ArrayList<>(hand);
        remainingCards.remove(playedCardIndex);

        return remainingCards.stream()
                .filter(card -> !card.isSuitChange())
                .collect(java.util.stream.Collectors.groupingBy(Card::getType, java.util.stream.Collectors.counting()))
                .entrySet()
                .stream()
                .max(Comparator.comparingLong(java.util.Map.Entry::getValue))
                .map(java.util.Map.Entry::getKey)
                .orElse(SUITS[0]);
    }

    private String normalizeChosenSuit(Card card, String chosenSuit) {
        if (!card.isSuitChange()) {
            return card.getType();
        }

        for (String suit : SUITS) {
            if (suit.equals(chosenSuit)) {
                return suit;
            }
        }

        return card.getType();
    }

    private void validatePlayerIndex(int playerIndex) {
        if (playerIndex < 0 || playerIndex >= playerCount) {
            throw new IllegalArgumentException("Unknown player index: " + playerIndex);
        }
    }

    private record CardEffectResult(int affectedPlayerIndex, int affectedCardCount) {}
    private record PlayedCardResult(Card card, int affectedPlayerIndex, int affectedCardCount) {}
}

package main;

import javax.swing.*;
import java.awt.*;
import java.awt.event.MouseAdapter;
import java.awt.event.MouseEvent;
import java.awt.geom.AffineTransform;
import java.util.ArrayList;
import java.util.List;

public class GamePanel extends JPanel implements Runnable {

    // screen settings
    final int originalTilesSize = 64;
    final int scale             = 2;
    public int tileSize         = originalTilesSize * scale;
    final int maxScreenCol      = 16;
    final int maxScreenRow      = 12;
    final int screenWidth       = (tileSize * maxScreenCol) / 2;
    final int screenHeight      = (tileSize * maxScreenRow) / 2;

    int FPS = 60;
    Thread gameThread;

    private static final long ANIMATION_DURATION_MS = 450;
    private static final int  AI_THINK_DELAY_MS     = 1600;

    private static final int    TABLE_MARGIN            = 24;
    private static final int    STACK_OFFSET            = 4;
    private static final int    MAX_VISIBLE_STACK       = 6;
    private static final double HAND_FAN_SPREAD_DEGREES = 36.0;
    private static final String[] SUIT_OPTIONS = {"Basto", "Copa", "Espada", "Oro"};

    private final int  cardWidth  = tileSize - 24;
    private final int  cardHeight = (int) Math.round(cardWidth * 1.45);
    private final Font hudFont      = UiFonts.bold(16f);
    private final Font smallHudFont = UiFonts.plain(14f);

    private final CopasGameState gameState;
    private volatile CardAnimation activeAnimation;
    private volatile boolean       aiTurnPending;
    private          Timer         aiTurnTimer;

    public GamePanel() {
        this.setPreferredSize(new Dimension(screenWidth, screenHeight));
        this.setBackground(new Color(16, 94, 58));
        this.setDoubleBuffered(true);
        this.gameState = new CopasGameState();
        this.addMouseListener(new TableMouseHandler());
    }

    public void startGameThread() {
        gameThread = new Thread(this);
        gameThread.start();
    }

    @Override
    public void run() {
        double drawInterval = 1_000_000_000.0 / FPS;
        double delta = 0;
        long lastTime = System.nanoTime();
        while (gameThread != null) {
            long now = System.nanoTime();
            delta += (now - lastTime) / drawInterval;
            lastTime = now;
            if (delta >= 1) { update(); repaint(); delta--; }
        }
    }

    public void update() {
        if (activeAnimation != null && activeAnimation.isDone()) {
            activeAnimation = null;
            if (gameState.isAiTurn() && !aiTurnPending)
                SwingUtilities.invokeLater(this::scheduleAiTurn);
        }
    }

    @Override
    public void paintComponent(Graphics g) {
        super.paintComponent(g);
        Graphics2D g2 = (Graphics2D) g;
        g2.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
        g2.setRenderingHint(RenderingHints.KEY_RENDERING,    RenderingHints.VALUE_RENDER_QUALITY);
        drawCenterCard(g2);
        drawPlayerHand(g2);
        drawDrawPile(g2);
        drawOpponentHandTop(g2);
        drawOpponentHandLeft(g2);
        drawOpponentHandRight(g2);
        if (activeAnimation != null) drawCardAnimation(g2);
        drawHud(g2);
        g2.dispose();
    }

    private void drawCenterCard(Graphics2D g2) {
        int x = (screenWidth  - cardWidth)  / 2;
        int y = (screenHeight - cardHeight) / 2 - 36;
        gameState.getTopCard().drawFront(g2, x, y, cardWidth, cardHeight);
    }

    private void drawPlayerHand(Graphics2D g2) {
        for (CardPlacement p : getPlayerHandPlacements()) {
            Graphics2D cg = (Graphics2D) g2.create();
            cg.rotate(p.angleRadians(), p.rotationPivotX(), p.rotationPivotY());
            p.card().drawFront(cg, p.x(), p.y(), cardWidth, cardHeight);
            if (gameState.isHumanTurn() && gameState.isHumanCardPlayable(p.handIndex())) {
                cg.setColor(new Color(255, 255, 255, 170));
                cg.setStroke(new BasicStroke(3f));
                cg.drawRoundRect(p.x(), p.y(), cardWidth, cardHeight, 16, 16);
            }
            cg.dispose();
        }
    }

    private void drawDrawPile(Graphics2D g2) {
        if (!gameState.hasAvailableDrawPile()) return;
        int vis   = Math.max(1, Math.min(gameState.getDrawPileSize(), MAX_VISIBLE_STACK));
        int baseX = screenWidth  - cardWidth  - TABLE_MARGIN;
        int baseY = screenHeight - cardHeight - TABLE_MARGIN;
        for (int i = vis - 1; i >= 0; i--)
            Card.drawBackImage(g2, baseX - i * STACK_OFFSET, baseY - i * STACK_OFFSET, cardWidth, cardHeight);
    }

    private void drawOpponentHandTop(Graphics2D g2) {
        drawOpponentHand(g2, 1, screenWidth / 2, TABLE_MARGIN + 16, true, false);
    }
    private void drawOpponentHandLeft(Graphics2D g2) {
        drawOpponentHand(g2, 2, TABLE_MARGIN + 16, screenHeight / 2, false, true);
    }
    private void drawOpponentHandRight(Graphics2D g2) {
        drawOpponentHand(g2, 3, screenWidth - TABLE_MARGIN - 16, screenHeight / 2, false, false);
    }

    private void drawOpponentHand(Graphics2D g2, int playerIndex, int cx, int cy,
                                   boolean horizontal, boolean isLeft) {
        int count = gameState.getPlayerCardCount(playerIndex);
        if (count <= 0) return;
        int vis = Math.min(count, 4);
        int cw  = cardWidth - 8;
        int ch  = (int) Math.round(cw * 1.45);
        if (horizontal)  drawFanH (g2, cx, cy, vis, cw, ch, count);
        else if (isLeft) drawFanVL(g2, cx, cy, vis, cw, ch, count);
        else             drawFanVR(g2, cx, cy, vis, cw, ch, count);
    }

    private void drawFanH(Graphics2D g2, int cx, int cy, int vis, int cw, int ch, int total) {
        double spread = vis == 1 ? 0 : 20.0, step = vis == 1 ? 0 : spread / (vis - 1);
        for (int i = 0; i < vis; i++) {
            double a = Math.toRadians(-spread / 2.0 + step * i);
            int x = clamp((int) Math.round(cx + Math.sin(a) * 30 - cw / 2.0), TABLE_MARGIN, screenWidth  - TABLE_MARGIN - cw);
            int y = (int) Math.round(Math.max(TABLE_MARGIN + 32, cy - Math.cos(a) * 30 - ch / 2.0));
            Graphics2D cg = (Graphics2D) g2.create();
            cg.rotate(a, x + cw / 2.0, y + ch * 0.5);
            Card.drawBackImage(cg, x, y, cw, ch);
            cg.dispose();
        }
        if (vis < total) { g2.setFont(smallHudFont); g2.setColor(Color.WHITE); g2.drawString("+" + (total - vis), cx - 12, cy + 40); }
    }

    private void drawFanVL(Graphics2D g2, int cx, int cy, int vis, int cw, int ch, int total) {
        double spread = vis == 1 ? 0 : 20.0, step = vis == 1 ? 0 : spread / (vis - 1);
        for (int i = 0; i < vis; i++) {
            double a = Math.toRadians(180.0 - spread / 2.0 + step * i);
            int x = (int) Math.round(Math.max(TABLE_MARGIN, cx + Math.cos(a) * 30 - cw / 2.0));
            int y = clamp((int) Math.round(cy + Math.sin(a) * 30 - ch / 2.0), TABLE_MARGIN, screenHeight - TABLE_MARGIN - ch);
            Graphics2D cg = (Graphics2D) g2.create();
            cg.rotate(a, x + cw / 2.0, y + ch / 2.0);
            Card.drawBackImage(cg, x, y, cw, ch);
            cg.dispose();
        }
        if (vis < total) { g2.setFont(smallHudFont); g2.setColor(Color.WHITE); g2.drawString("+" + (total - vis), cx - 50, cy + 24); }
    }

    private void drawFanVR(Graphics2D g2, int cx, int cy, int vis, int cw, int ch, int total) {
        double spread = vis == 1 ? 0 : 20.0, step = vis == 1 ? 0 : spread / (vis - 1);
        for (int i = 0; i < vis; i++) {
            double a = Math.toRadians(-spread / 2.0 + step * i);
            int x = clamp((int) Math.round(cx + Math.cos(a) * 30 - cw / 2.0), TABLE_MARGIN, screenWidth  - TABLE_MARGIN - cw);
            int y = clamp((int) Math.round(cy + Math.sin(a) * 30 - ch / 2.0), TABLE_MARGIN, screenHeight - TABLE_MARGIN - ch);
            Graphics2D cg = (Graphics2D) g2.create();
            cg.rotate(a, x + cw / 2.0, y + ch / 2.0);
            Card.drawBackImage(cg, x, y, cw, ch);
            cg.dispose();
        }
        if (vis < total) { g2.setFont(smallHudFont); g2.setColor(Color.WHITE); g2.drawString("+" + (total - vis), cx + 32, cy + 24); }
    }

    private static int clamp(int v, int lo, int hi) { return Math.max(lo, Math.min(hi, v)); }

    private void drawHud(Graphics2D g2) {
        g2.setFont(hudFont);
        g2.setColor(Color.WHITE);
        g2.drawString("Current turn: " + gameState.getPlayerName(gameState.getCurrentPlayerIndex()),
                TABLE_MARGIN, 28);
    }

    private void drawCardAnimation(Graphics2D g2) {
        double x = activeAnimation.currentX(), y = activeAnimation.currentY();
        double a = activeAnimation.currentAngle();
        Graphics2D cg = (Graphics2D) g2.create();
        cg.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
        cg.rotate(a, x + cardWidth / 2.0, y + cardHeight / 2.0);
        activeAnimation.draw(cg, (int) x, (int) y, cardWidth, cardHeight);
        cg.dispose();
    }

    private void scheduleAiTurn() {
        if (aiTurnPending) return;
        aiTurnPending = true;
        if (aiTurnTimer != null) aiTurnTimer.stop();
        aiTurnTimer = new Timer(AI_THINK_DELAY_MS, e -> {
            ((Timer) e.getSource()).stop();
            aiTurnPending = false;
            executeAiTurn();
        });
        aiTurnTimer.setRepeats(false);
        aiTurnTimer.start();
    }

    private void executeAiTurn() {
        if (!gameState.isAiTurn()) { repaint(); return; }
        CopasGameState.AiTurnResult result = gameState.stepAiTurn();
        if (result != null && result.cardPlayed() != null) {
            double[] from = playerHandCenter(result.playerIndex());
            int cx = (screenWidth  - cardWidth)  / 2;
            int cy = (screenHeight - cardHeight) / 2 - 36;
            activeAnimation = new CardAnimation(result.cardPlayed(), false,
                    from[0], from[1], cx, cy, 0.0, 0.0);
            activeAnimation.start();
        } else {
            if (gameState.isAiTurn() && !aiTurnPending) scheduleAiTurn();
        }
        repaint();
    }

    private double[] playerHandCenter(int playerIndex) {
        return switch (playerIndex) {
            case 1  -> new double[]{ screenWidth / 2.0 - cardWidth / 2.0, TABLE_MARGIN + 16 };
            case 2  -> new double[]{ TABLE_MARGIN + 16, screenHeight / 2.0 - cardHeight / 2.0 };
            case 3  -> new double[]{ screenWidth - TABLE_MARGIN - cardWidth - 16, screenHeight / 2.0 - cardHeight / 2.0 };
            default -> new double[]{ screenWidth / 2.0 - cardWidth / 2.0, screenHeight - cardHeight - TABLE_MARGIN };
        };
    }

    private List<CardPlacement> getPlayerHandPlacements() {
        List<Card> hand = gameState.getHumanHand();
        List<CardPlacement> list = new ArrayList<>();
        if (hand.isEmpty()) return list;
        double fanRadius   = cardHeight + 95.0;
        double pivotX      = screenWidth  / 2.0;
        double pivotY      = screenHeight + 220.0;
        double totalSpread = hand.size() == 1 ? 0 : HAND_FAN_SPREAD_DEGREES;
        double angleStep   = hand.size() == 1 ? 0 : totalSpread / (hand.size() - 1);
        double startAngle  = -totalSpread / 2.0;
        for (int i = 0; i < hand.size(); i++) {
            double ar  = Math.toRadians(startAngle + angleStep * i);
            int x = (int) Math.round(pivotX + Math.sin(ar) * fanRadius - cardWidth  / 2.0);
            int y = (int) Math.round(pivotY - Math.cos(ar) * fanRadius - cardHeight);
            double prx = x + cardWidth  / 2.0;
            double pry = y + cardHeight * 0.92;
            Shape hit  = AffineTransform.getRotateInstance(ar, prx, pry)
                    .createTransformedShape(new Rectangle(x, y, cardWidth, cardHeight));
            list.add(new CardPlacement(i, hand.get(i), x, y, ar, prx, pry, hit));
        }
        return list;
    }

    private Rectangle getDrawPileBounds() {
        if (!gameState.hasAvailableDrawPile()) return new Rectangle();
        int vis   = Math.max(1, Math.min(gameState.getDrawPileSize(), MAX_VISIBLE_STACK));
        int baseX = screenWidth  - cardWidth  - TABLE_MARGIN;
        int baseY = screenHeight - cardHeight - TABLE_MARGIN;
        return new Rectangle(baseX - (vis-1)*STACK_OFFSET, baseY - (vis-1)*STACK_OFFSET,
                cardWidth + (vis-1)*STACK_OFFSET, cardHeight + (vis-1)*STACK_OFFSET);
    }

    private void handleMouseClick(Point point) {
        if (gameState.isRoundOver() || activeAnimation != null || aiTurnPending) return;
        if (!gameState.isHumanTurn()) return;
        List<CardPlacement> ps = getPlayerHandPlacements();
        for (int i = ps.size() - 1; i >= 0; i--) {
            CardPlacement p = ps.get(i);
            if (!p.hitShape().contains(point)) continue;
            String suit = p.card().isSuitChange() ? requestSuitChoice() : null;
            if (p.card().isSuitChange() && suit == null) return;
            boolean played = gameState.playHumanCard(p.handIndex(), suit);
            if (played) {
                int dx = (screenWidth  - cardWidth)  / 2;
                int dy = (screenHeight - cardHeight) / 2 - 36;
                activeAnimation = new CardAnimation(p.card(), true,
                        p.x(), p.y(), dx, dy, p.angleRadians(), 0.0);
                activeAnimation.start();
            } else {
                Toolkit.getDefaultToolkit().beep();
            }
            repaint();
            return;
        }
        if (getDrawPileBounds().contains(point)) {
            gameState.drawForHuman();
            if (gameState.isAiTurn() && !aiTurnPending) scheduleAiTurn();
            repaint();
        }
    }

    private String requestSuitChoice() {
        Object sel = JOptionPane.showInputDialog(this, "Choose the next suit:", "Change Suit",
                JOptionPane.PLAIN_MESSAGE, null, SUIT_OPTIONS, gameState.getActiveSuit());
        return sel instanceof String s ? s : null;
    }

    private static class CardAnimation {
        private final Card card; private final boolean faceUp;
        private final double startX, startY, endX, endY, startAngle, endAngle;
        private long startTimeMs = -1;

        CardAnimation(Card card, boolean faceUp,
                      double sx, double sy, double ex, double ey, double sa, double ea) {
            this.card = card; this.faceUp = faceUp;
            startX = sx; startY = sy; endX = ex; endY = ey;
            startAngle = sa; endAngle = ea;
        }

        void    start()        { startTimeMs = System.currentTimeMillis(); }
        Card    card()         { return card; }
        boolean isDone()       { return startTimeMs >= 0 && progress() >= 1.0; }
        double  currentX()     { return lerp(startX, endX, ease()); }
        double  currentY()     { return lerp(startY, endY, ease()); }
        double  currentAngle() { return lerp(startAngle, endAngle, ease()); }

        void draw(Graphics2D g2, int x, int y, int w, int h) {
            if (faceUp) card.drawFront(g2, x, y, w, h);
            else        Card.drawBackImage(g2, x, y, w, h);
        }

        private double progress() {
            if (startTimeMs < 0) return 0;
            return Math.min(1.0, (double)(System.currentTimeMillis() - startTimeMs) / ANIMATION_DURATION_MS);
        }
        private double ease() {
            double t = progress();
            return t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2.0;
        }
        private static double lerp(double a, double b, double t) { return a + (b - a) * t; }
    }

    private record CardPlacement(int handIndex, Card card, int x, int y,
                                  double angleRadians, double rotationPivotX,
                                  double rotationPivotY, Shape hitShape) {}

    private class TableMouseHandler extends MouseAdapter {
        @Override public void mouseClicked(MouseEvent e) { handleMouseClick(e.getPoint()); }
    }
}

package main;

import javax.swing.*;
import java.awt.*;
import java.awt.event.MouseAdapter;
import java.awt.event.MouseEvent;
import java.awt.event.MouseMotionAdapter;
import java.awt.geom.AffineTransform;
import java.util.ArrayList;
import java.util.List;

public class GamePanel extends JPanel implements Runnable {

    // screen settings
    final int originalTilesSize = 64;
    final int scale             = 2;
    public int tileSize         = originalTilesSize * scale;
    final int maxScreenCol      = 16;
    final int maxScreenRow      = 12;
    final int screenWidth       = (tileSize * maxScreenCol) / 2;
    final int screenHeight      = (tileSize * maxScreenRow) / 2;

    int FPS = 60;
    Thread gameThread;

    private static final long ANIMATION_DURATION_MS = 450;
    private static final int  AI_THINK_DELAY_MS     = 1600;

    private static final int    TABLE_MARGIN            = 24;
    private static final int    STACK_OFFSET            = 4;
    private static final int    MAX_VISIBLE_STACK       = 6;
    private static final double HAND_FAN_SPREAD_DEGREES = 36.0;
    private static final String[] SUIT_OPTIONS = {"Basto", "Copa", "Espada", "Oro"};

    private final int  cardWidth  = tileSize - 24;
    private final int  cardHeight = (int) Math.round(cardWidth * 1.45);
    private final Font hudFont      = UiFonts.bold(16f);
    private final Font smallHudFont = UiFonts.plain(14f);

    private final CopasGameState gameState;
    private volatile CardAnimation activeAnimation;
    private volatile boolean       aiTurnPending;
    private          Timer         aiTurnTimer;

    public GamePanel() {
        this.setPreferredSize(new Dimension(screenWidth, screenHeight));
        this.setBackground(new Color(16, 94, 58));
        this.setDoubleBuffered(true);
        this.gameState = new CopasGameState();
        this.addMouseListener(new TableMouseHandler());
        this.addMouseMotionListener(new TableMouseMotionHandler());
    }

    public void startGameThread() {
        gameThread = new Thread(this);
        gameThread.start();
    }

    @Override
    public void run() {
        double drawInterval = 1_000_000_000.0 / FPS;
        double delta = 0;
        long lastTime = System.nanoTime();
        while (gameThread != null) {
            long now = System.nanoTime();
            delta += (now - lastTime) / drawInterval;
            lastTime = now;
            if (delta >= 1) { update(); repaint(); delta--; }
        }
    }

    public void update() {
        if (activeAnimation != null && activeAnimation.isDone()) {
            activeAnimation = null;
            if (gameState.isAiTurn() && !aiTurnPending)
                SwingUtilities.invokeLater(this::scheduleAiTurn);
        }
    }

    @Override
    public void paintComponent(Graphics g) {
        super.paintComponent(g);
        Graphics2D g2 = (Graphics2D) g;
        g2.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
        g2.setRenderingHint(RenderingHints.KEY_RENDERING,    RenderingHints.VALUE_RENDER_QUALITY);
        drawCenterCard(g2);
        drawPlayerHand(g2);
        drawDrawPile(g2);
        drawOpponentHandTop(g2);
        drawOpponentHandLeft(g2);
        drawOpponentHandRight(g2);
        if (activeAnimation != null) drawCardAnimation(g2);
        drawHud(g2);
        g2.dispose();
    }

    private void drawCenterCard(Graphics2D g2) {
        int x = (screenWidth  - cardWidth)  / 2;
        int y = (screenHeight - cardHeight) / 2 - 36;
        gameState.getTopCard().drawFront(g2, x, y, cardWidth, cardHeight);
    }

    private void drawPlayerHand(Graphics2D g2) {
        for (CardPlacement p : getPlayerHandPlacements()) {
            Graphics2D cg = (Graphics2D) g2.create();
            cg.rotate(p.angleRadians(), p.rotationPivotX(), p.rotationPivotY());
            p.card().drawFront(cg, p.x(), p.y(), cardWidth, cardHeight);
            if (gameState.isHumanTurn() && gameState.isHumanCardPlayable(p.handIndex())) {
                cg.setColor(new Color(255, 255, 255, 170));
                cg.setStroke(new BasicStroke(3f));
                cg.drawRoundRect(p.x(), p.y(), cardWidth, cardHeight, 16, 16);
            }
            cg.dispose();
        }
    }

    private void drawDrawPile(Graphics2D g2) {
        if (!gameState.hasAvailableDrawPile()) return;
        int vis   = Math.max(1, Math.min(gameState.getDrawPileSize(), MAX_VISIBLE_STACK));
        int baseX = screenWidth  - cardWidth  - TABLE_MARGIN;
        int baseY = screenHeight - cardHeight - TABLE_MARGIN;
        for (int i = vis - 1; i >= 0; i--)
            Card.drawBackImage(g2, baseX - i * STACK_OFFSET, baseY - i * STACK_OFFSET, cardWidth, cardHeight);
    }

    private void drawOpponentHandTop(Graphics2D g2) {
        drawOpponentHand(g2, 1, screenWidth / 2, TABLE_MARGIN + 16, true, false);
    }
    private void drawOpponentHandLeft(Graphics2D g2) {
        drawOpponentHand(g2, 2, TABLE_MARGIN + 16, screenHeight / 2, false, true);
    }
    private void drawOpponentHandRight(Graphics2D g2) {
        drawOpponentHand(g2, 3, screenWidth - TABLE_MARGIN - 16, screenHeight / 2, false, false);
    }

    private void drawOpponentHand(Graphics2D g2, int playerIndex, int cx, int cy,
                                   boolean horizontal, boolean isLeft) {
        int count = gameState.getPlayerCardCount(playerIndex);
        if (count <= 0) return;
        int vis = Math.min(count, 4);
        int cw  = cardWidth - 8;
        int ch  = (int) Math.round(cw * 1.45);
        if (horizontal)  drawFanH (g2, cx, cy, vis, cw, ch, count);
        else if (isLeft) drawFanVL(g2, cx, cy, vis, cw, ch, count);
        else             drawFanVR(g2, cx, cy, vis, cw, ch, count);
    }

    private void drawFanH(Graphics2D g2, int cx, int cy, int vis, int cw, int ch, int total) {
        double spread = vis == 1 ? 0 : 20.0, step = vis == 1 ? 0 : spread / (vis - 1);
        for (int i = 0; i < vis; i++) {
            double a = Math.toRadians(-spread / 2.0 + step * i);
            int x = clamp((int) Math.round(cx + Math.sin(a) * 30 - cw / 2.0), TABLE_MARGIN, screenWidth  - TABLE_MARGIN - cw);
            int y = (int) Math.round(Math.max(TABLE_MARGIN + 32, cy - Math.cos(a) * 30 - ch / 2.0));
            Graphics2D cg = (Graphics2D) g2.create();
            cg.rotate(a, x + cw / 2.0, y + ch * 0.5);
            Card.drawBackImage(cg, x, y, cw, ch);
            cg.dispose();
        }
        if (vis < total) { g2.setFont(smallHudFont); g2.setColor(Color.WHITE); g2.drawString("+" + (total - vis), cx - 12, cy + 40); }
    }

    private void drawFanVL(Graphics2D g2, int cx, int cy, int vis, int cw, int ch, int total) {
        double spread = vis == 1 ? 0 : 20.0, step = vis == 1 ? 0 : spread / (vis - 1);
        for (int i = 0; i < vis; i++) {
            double a = Math.toRadians(180.0 - spread / 2.0 + step * i);
            int x = (int) Math.round(Math.max(TABLE_MARGIN, cx + Math.cos(a) * 30 - cw / 2.0));
            int y = clamp((int) Math.round(cy + Math.sin(a) * 30 - ch / 2.0), TABLE_MARGIN, screenHeight - TABLE_MARGIN - ch);
            Graphics2D cg = (Graphics2D) g2.create();
            cg.rotate(a, x + cw / 2.0, y + ch / 2.0);
            Card.drawBackImage(cg, x, y, cw, ch);
            cg.dispose();
        }
        if (vis < total) { g2.setFont(smallHudFont); g2.setColor(Color.WHITE); g2.drawString("+" + (total - vis), cx - 50, cy + 24); }
    }

    private void drawFanVR(Graphics2D g2, int cx, int cy, int vis, int cw, int ch, int total) {
        double spread = vis == 1 ? 0 : 20.0, step = vis == 1 ? 0 : spread / (vis - 1);
        for (int i = 0; i < vis; i++) {
            double a = Math.toRadians(-spread / 2.0 + step * i);
            int x = clamp((int) Math.round(cx + Math.cos(a) * 30 - cw / 2.0), TABLE_MARGIN, screenWidth  - TABLE_MARGIN - cw);
            int y = clamp((int) Math.round(cy + Math.sin(a) * 30 - ch / 2.0), TABLE_MARGIN, screenHeight - TABLE_MARGIN - ch);
            Graphics2D cg = (Graphics2D) g2.create();
            cg.rotate(a, x + cw / 2.0, y + ch / 2.0);
            Card.drawBackImage(cg, x, y, cw, ch);
            cg.dispose();
        }
        if (vis < total) { g2.setFont(smallHudFont); g2.setColor(Color.WHITE); g2.drawString("+" + (total - vis), cx + 32, cy + 24); }
    }

    private static int clamp(int v, int lo, int hi) { return Math.max(lo, Math.min(hi, v)); }

    private void drawHud(Graphics2D g2) {
        g2.setFont(hudFont);
        g2.setColor(Color.WHITE);
        g2.drawString("Current turn: " + gameState.getPlayerName(gameState.getCurrentPlayerIndex()),
                TABLE_MARGIN, 28);
    }

    private void drawCardAnimation(Graphics2D g2) {
        double x = activeAnimation.currentX(), y = activeAnimation.currentY();
        double a = activeAnimation.currentAngle();
        Graphics2D cg = (Graphics2D) g2.create();
        cg.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
        cg.rotate(a, x + cardWidth / 2.0, y + cardHeight / 2.0);
        activeAnimation.draw(cg, (int) x, (int) y, cardWidth, cardHeight);
        cg.dispose();
    }

    private void scheduleAiTurn() {
        if (aiTurnPending) return;
        aiTurnPending = true;
        if (aiTurnTimer != null) aiTurnTimer.stop();
        aiTurnTimer = new Timer(AI_THINK_DELAY_MS, e -> {
            ((Timer) e.getSource()).stop();
            aiTurnPending = false;
            executeAiTurn();
        });
        aiTurnTimer.setRepeats(false);
        aiTurnTimer.start();
    }

    private void executeAiTurn() {
        if (!gameState.isAiTurn()) { repaint(); return; }
        CopasGameState.AiTurnResult result = gameState.stepAiTurn();
        if (result != null && result.cardPlayed() != null) {
            double[] from = playerHandCenter(result.playerIndex());
            int cx = (screenWidth  - cardWidth)  / 2;
            int cy = (screenHeight - cardHeight) / 2 - 36;
            activeAnimation = new CardAnimation(result.cardPlayed(), false,
                    from[0], from[1], cx, cy, 0.0, 0.0);
            activeAnimation.start();
        } else {
            if (gameState.isAiTurn() && !aiTurnPending) scheduleAiTurn();
        }
        repaint();
    }

    private double[] playerHandCenter(int playerIndex) {
        return switch (playerIndex) {
            case 1  -> new double[]{ screenWidth / 2.0 - cardWidth / 2.0, TABLE_MARGIN + 16 };
            case 2  -> new double[]{ TABLE_MARGIN + 16, screenHeight / 2.0 - cardHeight / 2.0 };
            case 3  -> new double[]{ screenWidth - TABLE_MARGIN - cardWidth - 16, screenHeight / 2.0 - cardHeight / 2.0 };
            default -> new double[]{ screenWidth / 2.0 - cardWidth / 2.0, screenHeight - cardHeight - TABLE_MARGIN };
        };
    }

    private List<CardPlacement> getPlayerHandPlacements() {
        List<Card> hand = gameState.getHumanHand();
        List<CardPlacement> list = new ArrayList<>();
        if (hand.isEmpty()) return list;
        double fanRadius   = cardHeight + 95.0;
        double pivotX      = screenWidth  / 2.0;
        double pivotY      = screenHeight + 220.0;
        double totalSpread = hand.size() == 1 ? 0 : HAND_FAN_SPREAD_DEGREES;
        double angleStep   = hand.size() == 1 ? 0 : totalSpread / (hand.size() - 1);
        double startAngle  = -totalSpread / 2.0;
        for (int i = 0; i < hand.size(); i++) {
            double ar  = Math.toRadians(startAngle + angleStep * i);
            int x = (int) Math.round(pivotX + Math.sin(ar) * fanRadius - cardWidth  / 2.0);
            int y = (int) Math.round(pivotY - Math.cos(ar) * fanRadius - cardHeight);
            double prx = x + cardWidth  / 2.0;
            double pry = y + cardHeight * 0.92;
            Shape hit  = AffineTransform.getRotateInstance(ar, prx, pry)
                    .createTransformedShape(new Rectangle(x, y, cardWidth, cardHeight));
            list.add(new CardPlacement(i, hand.get(i), x, y, ar, prx, pry, hit));
        }
        return list;
    }

    private Rectangle getDrawPileBounds() {
        if (!gameState.hasAvailableDrawPile()) return new Rectangle();
        int vis   = Math.max(1, Math.min(gameState.getDrawPileSize(), MAX_VISIBLE_STACK));
        int baseX = screenWidth  - cardWidth  - TABLE_MARGIN;
        int baseY = screenHeight - cardHeight - TABLE_MARGIN;
        return new Rectangle(baseX - (vis-1)*STACK_OFFSET, baseY - (vis-1)*STACK_OFFSET,
                cardWidth + (vis-1)*STACK_OFFSET, cardHeight + (vis-1)*STACK_OFFSET);
    }

    private void handleMouseClick(Point point) {
        if (gameState.isRoundOver() || activeAnimation != null || aiTurnPending) return;
        if (!gameState.isHumanTurn()) return;
        List<CardPlacement> ps = getPlayerHandPlacements();
        for (int i = ps.size() - 1; i >= 0; i--) {
            CardPlacement p = ps.get(i);
            if (!p.hitShape().contains(point)) continue;
            String suit = p.card().isSuitChange() ? requestSuitChoice() : null;
            if (p.card().isSuitChange() && suit == null) return;
            boolean played = gameState.playHumanCard(p.handIndex(), suit);
            if (played) {
                int dx = (screenWidth  - cardWidth)  / 2;
                int dy = (screenHeight - cardHeight) / 2 - 36;
                activeAnimation = new CardAnimation(p.card(), true,
                        p.x(), p.y(), dx, dy, p.angleRadians(), 0.0);
                activeAnimation.start();
            } else {
                Toolkit.getDefaultToolkit().beep();
            }
            repaint();
            return;
        }
        if (getDrawPileBounds().contains(point)) {
            gameState.drawForHuman();
            if (gameState.isAiTurn() && !aiTurnPending) scheduleAiTurn();
            repaint();
        }
    }

    private void updateCursor(Point point) {
        if (gameState.isRoundOver() || activeAnimation != null || aiTurnPending || !gameState.isHumanTurn()) {
            setCursor(Cursor.getDefaultCursor());
            return;
        }

        boolean onPlayableCard = false;
        for (CardPlacement p : getPlayerHandPlacements()) {
            if (!p.hitShape().contains(point)) continue;
            onPlayableCard = gameState.isHumanCardPlayable(p.handIndex());
            break;
        }

        boolean onDrawPile = getDrawPileBounds().contains(point) && gameState.canHumanDraw();
        setCursor((onPlayableCard || onDrawPile)
                ? Cursor.getPredefinedCursor(Cursor.HAND_CURSOR)
                : Cursor.getDefaultCursor());
    }

    private String requestSuitChoice() {
        Object sel = JOptionPane.showInputDialog(this, "Choose the next suit:", "Change Suit",
                JOptionPane.PLAIN_MESSAGE, null, SUIT_OPTIONS, gameState.getActiveSuit());
        return sel instanceof String s ? s : null;
    }

    private static class CardAnimation {
        private final Card card; private final boolean faceUp;
        private final double startX, startY, endX, endY, startAngle, endAngle;
        private long startTimeMs = -1;

        CardAnimation(Card card, boolean faceUp,
                      double sx, double sy, double ex, double ey, double sa, double ea) {
            this.card = card; this.faceUp = faceUp;
            startX = sx; startY = sy; endX = ex; endY = ey;
            startAngle = sa; endAngle = ea;
        }

        void    start()        { startTimeMs = System.currentTimeMillis(); }
        Card    card()         { return card; }
        boolean isDone()       { return startTimeMs >= 0 && progress() >= 1.0; }
        double  currentX()     { return lerp(startX, endX, ease()); }
        double  currentY()     { return lerp(startY, endY, ease()); }
        double  currentAngle() { return lerp(startAngle, endAngle, ease()); }

        void draw(Graphics2D g2, int x, int y, int w, int h) {
            if (faceUp) card.drawFront(g2, x, y, w, h);
            else        Card.drawBackImage(g2, x, y, w, h);
        }

        private double progress() {
            if (startTimeMs < 0) return 0;
            return Math.min(1.0, (double)(System.currentTimeMillis() - startTimeMs) / ANIMATION_DURATION_MS);
        }
        private double ease() {
            double t = progress();
            return t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2.0;
        }
        private static double lerp(double a, double b, double t) { return a + (b - a) * t; }
    }

    private record CardPlacement(int handIndex, Card card, int x, int y,
                                  double angleRadians, double rotationPivotX,
                                  double rotationPivotY, Shape hitShape) {}

    private class TableMouseHandler extends MouseAdapter {
        @Override public void mouseClicked(MouseEvent e) { handleMouseClick(e.getPoint()); }
    }

    private class TableMouseMotionHandler extends MouseMotionAdapter {
        @Override public void mouseMoved(MouseEvent e) { updateCursor(e.getPoint()); }
    }
}

package main;

import main.LocalMultiplayerProtocol.CardPayload;
import main.LocalMultiplayerProtocol.MultiplayerGameEvent;
import main.LocalMultiplayerProtocol.MultiplayerGameSnapshot;
import main.LocalMultiplayerProtocol.MultiplayerEventType;

import javax.swing.JOptionPane;
import javax.swing.JPanel;
import javax.swing.SwingUtilities;
import javax.swing.Timer;
import java.awt.BasicStroke;
import java.awt.Color;
import java.awt.Dimension;
import java.awt.Graphics;
import java.awt.Graphics2D;
import java.awt.Point;
import java.awt.Rectangle;
import java.awt.RenderingHints;
import java.awt.Shape;
import java.awt.Toolkit;
import java.awt.event.MouseAdapter;
import java.awt.event.MouseEvent;
import java.awt.geom.AffineTransform;
import java.util.ArrayList;
import java.util.Iterator;
import java.util.List;

public class MultiplayerGamePanel extends JPanel {
    private static final long ANIMATION_DURATION_MS = 420;
    private static final int TABLE_MARGIN = 24;
    private static final int STACK_OFFSET = 4;
    private static final int MAX_VISIBLE_STACK = 6;
    private static final double HAND_FAN_SPREAD_DEGREES = 36.0;
    private static final String[] SUIT_OPTIONS = {"Basto", "Copa", "Espada", "Oro"};

    final int originalTilesSize = 64;
    final int scale = 2;
    public int tileSize = originalTilesSize * scale;
    final int maxScreenCol = 16;
    final int maxScreenRow = 12;
    final int screenWidth = (tileSize * maxScreenCol) / 2;
    final int screenHeight = (tileSize * maxScreenRow) / 2;

    private final int cardWidth = tileSize - 24;
    private final int cardHeight = (int) Math.round(cardWidth * 1.45);
    private final MultiplayerGameController controller;
    private final Timer animationTimer;
    private final List<CardAnimation> activeAnimations = new ArrayList<>();

    private final java.awt.Font hudFont = UiFonts.bold(16f);
    private volatile MultiplayerGameSnapshot snapshot;

    public MultiplayerGamePanel(MultiplayerGameController controller, MultiplayerGameSnapshot initialSnapshot) {
        this.controller = controller;
        this.snapshot = initialSnapshot;

        setPreferredSize(new Dimension(screenWidth, screenHeight));
        setBackground(new Color(16, 94, 58));
        setDoubleBuffered(true);
        addMouseListener(new TableMouseHandler());

        controller.setListener(new MultiplayerGameController.Listener() {
            @Override
            public void onSnapshotUpdated(MultiplayerGameSnapshot updatedSnapshot) {
                handleSnapshotUpdated(updatedSnapshot);
            }

            @Override
            public void onError(String message) {
                JOptionPane.showMessageDialog(MultiplayerGamePanel.this, message, "Local multiplayer", JOptionPane.WARNING_MESSAGE);
            }

            @Override
            public void onDisconnected(String reason) {
                animationTimer.stop();
                JOptionPane.showMessageDialog(MultiplayerGamePanel.this, reason, "Connection closed", JOptionPane.INFORMATION_MESSAGE);
            }
        });

        animationTimer = new Timer(1000 / 60, _ -> {
            updateAnimations();
            repaint();
        });
        animationTimer.start();
    }

    @Override
    protected void paintComponent(Graphics g) {
        super.paintComponent(g);
        Graphics2D g2 = (Graphics2D) g;
        g2.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
        g2.setRenderingHint(RenderingHints.KEY_RENDERING, RenderingHints.VALUE_RENDER_QUALITY);

        drawCenterCard(g2);
        drawOpponentHand(g2);
        drawPlayerHand(g2);
        drawDrawPile(g2);
        drawAnimations(g2);
        drawHud(g2);
        g2.dispose();
    }

    @Override
    public void removeNotify() {
        animationTimer.stop();
        super.removeNotify();
    }

    private void handleSnapshotUpdated(MultiplayerGameSnapshot updatedSnapshot) {
        MultiplayerGameSnapshot previousSnapshot = snapshot;
        snapshot = updatedSnapshot;
        buildAnimations(previousSnapshot, updatedSnapshot);
        if (updatedSnapshot.roundOver() && (previousSnapshot == null || !previousSnapshot.roundOver())) {
            SwingUtilities.invokeLater(() -> JOptionPane.showMessageDialog(
                    this,
                    updatedSnapshot.statusMessage(),
                    "Round over",
                    JOptionPane.INFORMATION_MESSAGE
            ));
        }
        repaint();
    }

    private void buildAnimations(MultiplayerGameSnapshot previousSnapshot, MultiplayerGameSnapshot updatedSnapshot) {
        activeAnimations.clear();
        if (previousSnapshot == null || updatedSnapshot.recentEvent() == null) {
            return;
        }

        MultiplayerGameEvent event = updatedSnapshot.recentEvent();
        switch (event.type()) {
            case ROUND_START -> {
            }
            case PLAY_CARD -> buildPlayAnimation(previousSnapshot, event);
            case DRAW_CARD -> buildDrawAnimation(event);
        }
    }

    private void buildPlayAnimation(MultiplayerGameSnapshot previousSnapshot, MultiplayerGameEvent event) {
        double fromX;
        double fromY;
        double fromAngle;

        if (event.actorIsLocal() && event.card() != null) {
            CardPlacement placement = findPlacement(previousSnapshot.localHand(), event.card());
            if (placement != null) {
                fromX = placement.x();
                fromY = placement.y();
                fromAngle = placement.angleRadians();
            } else {
                fromX = localHandAnchorX();
                fromY = localHandAnchorY();
                fromAngle = 0.0;
            }
        } else {
            fromX = opponentHandAnchorX();
            fromY = opponentHandAnchorY();
            fromAngle = 0.0;
        }

        activeAnimations.add(new CardAnimation(event.card(), true,
                fromX, fromY, centerCardX(), centerCardY(), fromAngle, 0.0));
        activeAnimations.getLast().start();

        if (event.affectedCardCount() > 0) {
            activeAnimations.add(new CardAnimation(null, false,
                    drawPileX(), drawPileY(),
                    event.targetIsLocal() ? localHandAnchorX() : opponentHandAnchorX(),
                    event.targetIsLocal() ? localHandAnchorY() : opponentHandAnchorY(),
                    0.0, 0.0));
            activeAnimations.getLast().start();
        }
    }

    private void buildDrawAnimation(MultiplayerGameEvent event) {
        boolean faceUp = event.actorIsLocal() && event.card() != null;
        activeAnimations.add(new CardAnimation(event.card(), faceUp,
                drawPileX(), drawPileY(),
                event.actorIsLocal() ? localHandAnchorX() : opponentHandAnchorX(),
                event.actorIsLocal() ? localHandAnchorY() : opponentHandAnchorY(),
                0.0, 0.0));
        activeAnimations.getLast().start();
    }

    private void updateAnimations() {
        Iterator<CardAnimation> iterator = activeAnimations.iterator();
        while (iterator.hasNext()) {
            if (iterator.next().isDone()) {
                iterator.remove();
            }
        }
    }

    private void drawCenterCard(Graphics2D g2) {
        if (snapshot == null || snapshot.topCard() == null) {
            return;
        }
        snapshot.topCard().toCard().drawFront(g2, centerCardX(), centerCardY(), cardWidth, cardHeight);
    }

    private void drawPlayerHand(Graphics2D g2) {
        if (snapshot == null) {
            return;
        }
        for (CardPlacement placement : getPlayerHandPlacements(snapshot.localHand())) {
            Graphics2D cg = (Graphics2D) g2.create();
            cg.rotate(placement.angleRadians(), placement.rotationPivotX(), placement.rotationPivotY());
            placement.card().toCard().drawFront(cg, placement.x(), placement.y(), cardWidth, cardHeight);
            if (snapshot.localTurn() && snapshot.playableCardIndexes().contains(placement.handIndex())) {
                cg.setColor(new Color(255, 255, 255, 170));
                cg.setStroke(new BasicStroke(3f));
                cg.drawRoundRect(placement.x(), placement.y(), cardWidth, cardHeight, 16, 16);
            }
            cg.dispose();
        }
    }

    private void drawOpponentHand(Graphics2D g2) {
        if (snapshot == null || snapshot.opponentCardCount() <= 0) {
            return;
        }

        int visibleCards = Math.min(snapshot.opponentCardCount(), 6);
        int opponentCardWidth = cardWidth - 8;
        int opponentCardHeight = (int) Math.round(opponentCardWidth * 1.45);
        double spread = visibleCards == 1 ? 0.0 : 22.0;
        double step = visibleCards == 1 ? 0.0 : spread / (visibleCards - 1);

        for (int index = 0; index < visibleCards; index++) {
            double angle = Math.toRadians(-spread / 2.0 + step * index);
            int x = clamp((int) Math.round(screenWidth / 2.0 + Math.sin(angle) * 36 - opponentCardWidth / 2.0),
                    TABLE_MARGIN, screenWidth - TABLE_MARGIN - opponentCardWidth);
            int y = (int) Math.round(Math.max(TABLE_MARGIN + 24,
                    TABLE_MARGIN + 20 - Math.cos(angle) * 22));
            Graphics2D cg = (Graphics2D) g2.create();
            cg.rotate(angle, x + opponentCardWidth / 2.0, y + opponentCardHeight * 0.52);
            Card.drawBackImage(cg, x, y, opponentCardWidth, opponentCardHeight);
            cg.dispose();
        }
    }

    private void drawDrawPile(Graphics2D g2) {
        if (snapshot == null || snapshot.drawPileSize() <= 0) {
            return;
        }
        int visibleCards = Math.max(1, Math.min(snapshot.drawPileSize(), MAX_VISIBLE_STACK));
        for (int index = visibleCards - 1; index >= 0; index--) {
            Card.drawBackImage(g2,
                    drawPileX() - index * STACK_OFFSET,
                    drawPileY() - index * STACK_OFFSET,
                    cardWidth,
                    cardHeight);
        }
    }

    private void drawAnimations(Graphics2D g2) {
        for (CardAnimation animation : activeAnimations) {
            Graphics2D cg = (Graphics2D) g2.create();
            cg.rotate(animation.currentAngle(), animation.currentX() + cardWidth / 2.0, animation.currentY() + cardHeight / 2.0);
            animation.draw(cg, (int) animation.currentX(), (int) animation.currentY(), cardWidth, cardHeight);
            cg.dispose();
        }
    }

    private void drawHud(Graphics2D g2) {
        if (snapshot == null) {
            return;
        }
        g2.setFont(hudFont);
        g2.setColor(Color.WHITE);
        g2.drawString("Current turn: " + snapshot.currentTurnName(), TABLE_MARGIN, 28);
    }

    private List<CardPlacement> getPlayerHandPlacements(List<CardPayload> hand) {
        List<CardPlacement> placements = new ArrayList<>();
        if (hand == null || hand.isEmpty()) {
            return placements;
        }
        double fanRadius = cardHeight + 95.0;
        double pivotX = screenWidth / 2.0;
        double pivotY = screenHeight + 220.0;
        double totalSpread = hand.size() == 1 ? 0 : HAND_FAN_SPREAD_DEGREES;
        double angleStep = hand.size() == 1 ? 0 : totalSpread / (hand.size() - 1);
        double startAngle = -totalSpread / 2.0;
        for (int index = 0; index < hand.size(); index++) {
            double angleRadians = Math.toRadians(startAngle + angleStep * index);
            int x = (int) Math.round(pivotX + Math.sin(angleRadians) * fanRadius - cardWidth / 2.0);
            int y = (int) Math.round(pivotY - Math.cos(angleRadians) * fanRadius - cardHeight);
            double pivotRotationX = x + cardWidth / 2.0;
            double pivotRotationY = y + cardHeight * 0.92;
            Shape hitShape = AffineTransform.getRotateInstance(angleRadians, pivotRotationX, pivotRotationY)
                    .createTransformedShape(new Rectangle(x, y, cardWidth, cardHeight));
            placements.add(new CardPlacement(index, hand.get(index), x, y, angleRadians, pivotRotationX, pivotRotationY, hitShape));
        }
        return placements;
    }

    private CardPlacement findPlacement(List<CardPayload> hand, CardPayload card) {
        if (card == null) {
            return null;
        }
        for (CardPlacement placement : getPlayerHandPlacements(hand)) {
            if (placement.card().equals(card)) {
                return placement;
            }
        }
        return null;
    }

    private Rectangle getDrawPileBounds() {
        if (snapshot == null || snapshot.drawPileSize() <= 0) {
            return new Rectangle();
        }
        int visibleCards = Math.max(1, Math.min(snapshot.drawPileSize(), MAX_VISIBLE_STACK));
        return new Rectangle(
                drawPileX() - (visibleCards - 1) * STACK_OFFSET,
                drawPileY() - (visibleCards - 1) * STACK_OFFSET,
                cardWidth + (visibleCards - 1) * STACK_OFFSET,
                cardHeight + (visibleCards - 1) * STACK_OFFSET
        );
    }

    private void handleMouseClick(Point point) {
        if (snapshot == null || snapshot.roundOver() || !activeAnimations.isEmpty()) {
            return;
        }
        if (!snapshot.localTurn()) {
            Toolkit.getDefaultToolkit().beep();
            return;
        }

        List<CardPlacement> placements = getPlayerHandPlacements(snapshot.localHand());
        for (int index = placements.size() - 1; index >= 0; index--) {
            CardPlacement placement = placements.get(index);
            if (!placement.hitShape().contains(point)) {
                continue;
            }
            if (!snapshot.playableCardIndexes().contains(placement.handIndex())) {
                Toolkit.getDefaultToolkit().beep();
                return;
            }
            String chosenSuit = placement.card().number() == 7 ? requestSuitChoice() : null;
            if (placement.card().number() == 7 && chosenSuit == null) {
                return;
            }
            controller.playCard(placement.handIndex(), chosenSuit);
            return;
        }

        if (getDrawPileBounds().contains(point) && snapshot.canDraw()) {
            controller.drawCard();
        }
    }

    private String requestSuitChoice() {
        Object selection = JOptionPane.showInputDialog(
                this,
                "Choose the next suit:",
                "Change Suit",
                JOptionPane.PLAIN_MESSAGE,
                null,
                SUIT_OPTIONS,
                snapshot.activeSuit()
        );
        return selection instanceof String suit ? suit : null;
    }

    private int centerCardX() {
        return (screenWidth - cardWidth) / 2;
    }

    private int centerCardY() {
        return (screenHeight - cardHeight) / 2 - 36;
    }

    private int drawPileX() {
        return screenWidth - cardWidth - TABLE_MARGIN;
    }

    private int drawPileY() {
        return screenHeight - cardHeight - TABLE_MARGIN;
    }

    private int localHandAnchorX() {
        return screenWidth / 2 - cardWidth / 2;
    }

    private int localHandAnchorY() {
        return screenHeight - cardHeight - TABLE_MARGIN;
    }

    private int opponentHandAnchorX() {
        return screenWidth / 2 - cardWidth / 2;
    }

    private int opponentHandAnchorY() {
        return TABLE_MARGIN + 16;
    }

    private static int clamp(int value, int min, int max) {
        return Math.max(min, Math.min(max, value));
    }

    private static class CardAnimation {
        private final CardPayload card;
        private final boolean faceUp;
        private final double startX;
        private final double startY;
        private final double endX;
        private final double endY;
        private final double startAngle;
        private final double endAngle;
        private long startTimeMs = -1;

        CardAnimation(CardPayload card, boolean faceUp, double startX, double startY,
                      double endX, double endY, double startAngle, double endAngle) {
            this.card = card;
            this.faceUp = faceUp;
            this.startX = startX;
            this.startY = startY;
            this.endX = endX;
            this.endY = endY;
            this.startAngle = startAngle;
            this.endAngle = endAngle;
        }

        void start() {
            startTimeMs = System.currentTimeMillis();
        }

        boolean isDone() {
            return startTimeMs >= 0 && progress() >= 1.0;
        }

        double currentX() {
            return lerp(startX, endX, ease());
        }

        double currentY() {
            return lerp(startY, endY, ease());
        }

        double currentAngle() {
            return lerp(startAngle, endAngle, ease());
        }

        void draw(Graphics2D g2, int x, int y, int width, int height) {
            if (faceUp && card != null) {
                card.toCard().drawFront(g2, x, y, width, height);
            } else {
                Card.drawBackImage(g2, x, y, width, height);
            }
        }

        private double progress() {
            if (startTimeMs < 0) {
                return 0.0;
            }
            return Math.min(1.0, (double) (System.currentTimeMillis() - startTimeMs) / ANIMATION_DURATION_MS);
        }

        private double ease() {
            double t = progress();
            return t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2.0;
        }

        private static double lerp(double start, double end, double amount) {
            return start + (end - start) * amount;
        }
    }

    private record CardPlacement(int handIndex, CardPayload card, int x, int y,
                                 double angleRadians, double rotationPivotX,
                                 double rotationPivotY, Shape hitShape) {
    }

    private class TableMouseHandler extends MouseAdapter {
        @Override
        public void mouseClicked(MouseEvent e) {
            handleMouseClick(e.getPoint());
        }
    }
}

package main;

import main.LocalMultiplayerProtocol.CardPayload;
import main.LocalMultiplayerProtocol.MultiplayerGameEvent;
import main.LocalMultiplayerProtocol.MultiplayerGameSnapshot;
import main.LocalMultiplayerProtocol.MultiplayerEventType;

import javax.swing.JOptionPane;
import javax.swing.JPanel;
import javax.swing.SwingUtilities;
import javax.swing.Timer;
import java.awt.BasicStroke;
import java.awt.Color;
import java.awt.Dimension;
import java.awt.Graphics;
import java.awt.Graphics2D;
import java.awt.Point;
import java.awt.Rectangle;
import java.awt.RenderingHints;
import java.awt.Shape;
import java.awt.Toolkit;
import java.awt.event.MouseAdapter;
import java.awt.event.MouseEvent;
import java.awt.event.MouseMotionAdapter;
import java.awt.geom.AffineTransform;
import java.util.ArrayList;
import java.util.Iterator;
import java.util.List;

public class MultiplayerGamePanel extends JPanel {
    private static final long ANIMATION_DURATION_MS = 420;
    private static final int TABLE_MARGIN = 24;
    private static final int STACK_OFFSET = 4;
    private static final int MAX_VISIBLE_STACK = 6;
    private static final double HAND_FAN_SPREAD_DEGREES = 36.0;
    private static final String[] SUIT_OPTIONS = {"Basto", "Copa", "Espada", "Oro"};

    final int originalTilesSize = 64;
    final int scale = 2;
    public int tileSize = originalTilesSize * scale;
    final int maxScreenCol = 16;
    final int maxScreenRow = 12;
    final int screenWidth = (tileSize * maxScreenCol) / 2;
    final int screenHeight = (tileSize * maxScreenRow) / 2;

    private final int cardWidth = tileSize - 24;
    private final int cardHeight = (int) Math.round(cardWidth * 1.45);
    private final MultiplayerGameController controller;
    private final Timer animationTimer;
    private final List<CardAnimation> activeAnimations = new ArrayList<>();

    private final java.awt.Font hudFont = UiFonts.bold(16f);
    private volatile MultiplayerGameSnapshot snapshot;

    public MultiplayerGamePanel(MultiplayerGameController controller, MultiplayerGameSnapshot initialSnapshot) {
        this.controller = controller;
        this.snapshot = initialSnapshot;

        setPreferredSize(new Dimension(screenWidth, screenHeight));
        setBackground(new Color(16, 94, 58));
        setDoubleBuffered(true);
        addMouseListener(new TableMouseHandler());
        addMouseMotionListener(new TableMouseMotionHandler());

        controller.setListener(new MultiplayerGameController.Listener() {
            @Override
            public void onSnapshotUpdated(MultiplayerGameSnapshot updatedSnapshot) {
                handleSnapshotUpdated(updatedSnapshot);
            }

            @Override
            public void onError(String message) {
                JOptionPane.showMessageDialog(MultiplayerGamePanel.this, message, "Local multiplayer", JOptionPane.WARNING_MESSAGE);
            }

            @Override
            public void onDisconnected(String reason) {
                animationTimer.stop();
                JOptionPane.showMessageDialog(MultiplayerGamePanel.this, reason, "Connection closed", JOptionPane.INFORMATION_MESSAGE);
            }
        });

        animationTimer = new Timer(1000 / 60, _ -> {
            updateAnimations();
            repaint();
        });
        animationTimer.start();
    }

    @Override
    protected void paintComponent(Graphics g) {
        super.paintComponent(g);
        Graphics2D g2 = (Graphics2D) g;
        g2.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
        g2.setRenderingHint(RenderingHints.KEY_RENDERING, RenderingHints.VALUE_RENDER_QUALITY);

        drawCenterCard(g2);
        drawOpponentHand(g2);
        drawPlayerHand(g2);
        drawDrawPile(g2);
        drawAnimations(g2);
        drawHud(g2);
        g2.dispose();
    }

    @Override
    public void removeNotify() {
        animationTimer.stop();
        super.removeNotify();
    }

    private void handleSnapshotUpdated(MultiplayerGameSnapshot updatedSnapshot) {
        MultiplayerGameSnapshot previousSnapshot = snapshot;
        snapshot = updatedSnapshot;
        buildAnimations(previousSnapshot, updatedSnapshot);
        if (updatedSnapshot.roundOver() && (previousSnapshot == null || !previousSnapshot.roundOver())) {
            SwingUtilities.invokeLater(() -> JOptionPane.showMessageDialog(
                    this,
                    updatedSnapshot.statusMessage(),
                    "Round over",
                    JOptionPane.INFORMATION_MESSAGE
            ));
        }
        repaint();
    }

    private void buildAnimations(MultiplayerGameSnapshot previousSnapshot, MultiplayerGameSnapshot updatedSnapshot) {
        activeAnimations.clear();
        if (previousSnapshot == null || updatedSnapshot.recentEvent() == null) {
            return;
        }

        MultiplayerGameEvent event = updatedSnapshot.recentEvent();
        switch (event.type()) {
            case ROUND_START -> {
            }
            case PLAY_CARD -> buildPlayAnimation(previousSnapshot, event);
            case DRAW_CARD -> buildDrawAnimation(event);
        }
    }

    private void buildPlayAnimation(MultiplayerGameSnapshot previousSnapshot, MultiplayerGameEvent event) {
        double fromX;
        double fromY;
        double fromAngle;

        if (event.actorIsLocal() && event.card() != null) {
            CardPlacement placement = findPlacement(previousSnapshot.localHand(), event.card());
            if (placement != null) {
                fromX = placement.x();
                fromY = placement.y();
                fromAngle = placement.angleRadians();
            } else {
                fromX = localHandAnchorX();
                fromY = localHandAnchorY();
                fromAngle = 0.0;
            }
        } else {
            fromX = opponentHandAnchorX();
            fromY = opponentHandAnchorY();
            fromAngle = 0.0;
        }

        activeAnimations.add(new CardAnimation(event.card(), true,
                fromX, fromY, centerCardX(), centerCardY(), fromAngle, 0.0));
        activeAnimations.getLast().start();

        if (event.affectedCardCount() > 0) {
            activeAnimations.add(new CardAnimation(null, false,
                    drawPileX(), drawPileY(),
                    event.targetIsLocal() ? localHandAnchorX() : opponentHandAnchorX(),
                    event.targetIsLocal() ? localHandAnchorY() : opponentHandAnchorY(),
                    0.0, 0.0));
            activeAnimations.getLast().start();
        }
    }

    private void buildDrawAnimation(MultiplayerGameEvent event) {
        boolean faceUp = event.actorIsLocal() && event.card() != null;
        activeAnimations.add(new CardAnimation(event.card(), faceUp,
                drawPileX(), drawPileY(),
                event.actorIsLocal() ? localHandAnchorX() : opponentHandAnchorX(),
                event.actorIsLocal() ? localHandAnchorY() : opponentHandAnchorY(),
                0.0, 0.0));
        activeAnimations.getLast().start();
    }

    private void updateAnimations() {
        Iterator<CardAnimation> iterator = activeAnimations.iterator();
        while (iterator.hasNext()) {
            if (iterator.next().isDone()) {
                iterator.remove();
            }
        }
    }

    private void drawCenterCard(Graphics2D g2) {
        if (snapshot == null || snapshot.topCard() == null) {
            return;
        }
        snapshot.topCard().toCard().drawFront(g2, centerCardX(), centerCardY(), cardWidth, cardHeight);
    }

    private void drawPlayerHand(Graphics2D g2) {
        if (snapshot == null) {
            return;
        }
        for (CardPlacement placement : getPlayerHandPlacements(snapshot.localHand())) {
            Graphics2D cg = (Graphics2D) g2.create();
            cg.rotate(placement.angleRadians(), placement.rotationPivotX(), placement.rotationPivotY());
            placement.card().toCard().drawFront(cg, placement.x(), placement.y(), cardWidth, cardHeight);
            if (snapshot.localTurn() && snapshot.playableCardIndexes().contains(placement.handIndex())) {
                cg.setColor(new Color(255, 255, 255, 170));
                cg.setStroke(new BasicStroke(3f));
                cg.drawRoundRect(placement.x(), placement.y(), cardWidth, cardHeight, 16, 16);
            }
            cg.dispose();
        }
    }

    private void drawOpponentHand(Graphics2D g2) {
        if (snapshot == null || snapshot.opponentCardCount() <= 0) {
            return;
        }

        int visibleCards = Math.min(snapshot.opponentCardCount(), 6);
        int opponentCardWidth = cardWidth - 8;
        int opponentCardHeight = (int) Math.round(opponentCardWidth * 1.45);
        double spread = visibleCards == 1 ? 0.0 : 22.0;
        double step = visibleCards == 1 ? 0.0 : spread / (visibleCards - 1);

        for (int index = 0; index < visibleCards; index++) {
            double angle = Math.toRadians(-spread / 2.0 + step * index);
            int x = clamp((int) Math.round(screenWidth / 2.0 + Math.sin(angle) * 36 - opponentCardWidth / 2.0),
                    TABLE_MARGIN, screenWidth - TABLE_MARGIN - opponentCardWidth);
            int y = (int) Math.round(Math.max(TABLE_MARGIN + 24,
                    TABLE_MARGIN + 20 - Math.cos(angle) * 22));
            Graphics2D cg = (Graphics2D) g2.create();
            cg.rotate(angle, x + opponentCardWidth / 2.0, y + opponentCardHeight * 0.52);
            Card.drawBackImage(cg, x, y, opponentCardWidth, opponentCardHeight);
            cg.dispose();
        }
    }

    private void drawDrawPile(Graphics2D g2) {
        if (snapshot == null || snapshot.drawPileSize() <= 0) {
            return;
        }
        int visibleCards = Math.max(1, Math.min(snapshot.drawPileSize(), MAX_VISIBLE_STACK));
        for (int index = visibleCards - 1; index >= 0; index--) {
            Card.drawBackImage(g2,
                    drawPileX() - index * STACK_OFFSET,
                    drawPileY() - index * STACK_OFFSET,
                    cardWidth,
                    cardHeight);
        }
    }

    private void drawAnimations(Graphics2D g2) {
        for (CardAnimation animation : activeAnimations) {
            Graphics2D cg = (Graphics2D) g2.create();
            cg.rotate(animation.currentAngle(), animation.currentX() + cardWidth / 2.0, animation.currentY() + cardHeight / 2.0);
            animation.draw(cg, (int) animation.currentX(), (int) animation.currentY(), cardWidth, cardHeight);
            cg.dispose();
        }
    }

    private void drawHud(Graphics2D g2) {
        if (snapshot == null) {
            return;
        }
        g2.setFont(hudFont);
        g2.setColor(Color.WHITE);
        g2.drawString("Current turn: " + snapshot.currentTurnName(), TABLE_MARGIN, 28);
    }

    private List<CardPlacement> getPlayerHandPlacements(List<CardPayload> hand) {
        List<CardPlacement> placements = new ArrayList<>();
        if (hand == null || hand.isEmpty()) {
            return placements;
        }
        double fanRadius = cardHeight + 95.0;
        double pivotX = screenWidth / 2.0;
        double pivotY = screenHeight + 220.0;
        double totalSpread = hand.size() == 1 ? 0 : HAND_FAN_SPREAD_DEGREES;
        double angleStep = hand.size() == 1 ? 0 : totalSpread / (hand.size() - 1);
        double startAngle = -totalSpread / 2.0;
        for (int index = 0; index < hand.size(); index++) {
            double angleRadians = Math.toRadians(startAngle + angleStep * index);
            int x = (int) Math.round(pivotX + Math.sin(angleRadians) * fanRadius - cardWidth / 2.0);
            int y = (int) Math.round(pivotY - Math.cos(angleRadians) * fanRadius - cardHeight);
            double pivotRotationX = x + cardWidth / 2.0;
            double pivotRotationY = y + cardHeight * 0.92;
            Shape hitShape = AffineTransform.getRotateInstance(angleRadians, pivotRotationX, pivotRotationY)
                    .createTransformedShape(new Rectangle(x, y, cardWidth, cardHeight));
            placements.add(new CardPlacement(index, hand.get(index), x, y, angleRadians, pivotRotationX, pivotRotationY, hitShape));
        }
        return placements;
    }

    private CardPlacement findPlacement(List<CardPayload> hand, CardPayload card) {
        if (card == null) {
            return null;
        }
        for (CardPlacement placement : getPlayerHandPlacements(hand)) {
            if (placement.card().equals(card)) {
                return placement;
            }
        }
        return null;
    }

    private Rectangle getDrawPileBounds() {
        if (snapshot == null || snapshot.drawPileSize() <= 0) {
            return new Rectangle();
        }
        int visibleCards = Math.max(1, Math.min(snapshot.drawPileSize(), MAX_VISIBLE_STACK));
        return new Rectangle(
                drawPileX() - (visibleCards - 1) * STACK_OFFSET,
                drawPileY() - (visibleCards - 1) * STACK_OFFSET,
                cardWidth + (visibleCards - 1) * STACK_OFFSET,
                cardHeight + (visibleCards - 1) * STACK_OFFSET
        );
    }

    private void handleMouseClick(Point point) {
        if (snapshot == null || snapshot.roundOver() || !activeAnimations.isEmpty()) {
            return;
        }
        if (!snapshot.localTurn()) {
            Toolkit.getDefaultToolkit().beep();
            return;
        }

        List<CardPlacement> placements = getPlayerHandPlacements(snapshot.localHand());
        for (int index = placements.size() - 1; index >= 0; index--) {
            CardPlacement placement = placements.get(index);
            if (!placement.hitShape().contains(point)) {
                continue;
            }
            if (!snapshot.playableCardIndexes().contains(placement.handIndex())) {
                Toolkit.getDefaultToolkit().beep();
                return;
            }
            String chosenSuit = placement.card().number() == 7 ? requestSuitChoice() : null;
            if (placement.card().number() == 7 && chosenSuit == null) {
                return;
            }
            controller.playCard(placement.handIndex(), chosenSuit);
            return;
        }

        if (getDrawPileBounds().contains(point) && snapshot.canDraw()) {
            controller.drawCard();
        }
    }

    private void updateCursor(Point point) {
        if (snapshot == null || snapshot.roundOver() || !snapshot.localTurn() || !activeAnimations.isEmpty()) {
            setCursor(java.awt.Cursor.getDefaultCursor());
            return;
        }

        boolean onPlayableCard = false;
        List<CardPlacement> placements = getPlayerHandPlacements(snapshot.localHand());
        for (CardPlacement placement : placements) {
            if (!placement.hitShape().contains(point)) {
                continue;
            }
            onPlayableCard = snapshot.playableCardIndexes().contains(placement.handIndex());
            break;
        }

        boolean onDrawPile = getDrawPileBounds().contains(point) && snapshot.canDraw();
        setCursor((onPlayableCard || onDrawPile)
                ? java.awt.Cursor.getPredefinedCursor(java.awt.Cursor.HAND_CURSOR)
                : java.awt.Cursor.getDefaultCursor());
    }

    private String requestSuitChoice() {
        Object selection = JOptionPane.showInputDialog(
                this,
                "Choose the next suit:",
                "Change Suit",
                JOptionPane.PLAIN_MESSAGE,
                null,
                SUIT_OPTIONS,
                snapshot.activeSuit()
        );
        return selection instanceof String suit ? suit : null;
    }

    private int centerCardX() {
        return (screenWidth - cardWidth) / 2;
    }

    private int centerCardY() {
        return (screenHeight - cardHeight) / 2 - 36;
    }

    private int drawPileX() {
        return screenWidth - cardWidth - TABLE_MARGIN;
    }

    private int drawPileY() {
        return screenHeight - cardHeight - TABLE_MARGIN;
    }

    private int localHandAnchorX() {
        return screenWidth / 2 - cardWidth / 2;
    }

    private int localHandAnchorY() {
        return screenHeight - cardHeight - TABLE_MARGIN;
    }

    private int opponentHandAnchorX() {
        return screenWidth / 2 - cardWidth / 2;
    }

    private int opponentHandAnchorY() {
        return TABLE_MARGIN + 16;
    }

    private static int clamp(int value, int min, int max) {
        return Math.max(min, Math.min(max, value));
    }

    private static class CardAnimation {
        private final CardPayload card;
        private final boolean faceUp;
        private final double startX;
        private final double startY;
        private final double endX;
        private final double endY;
        private final double startAngle;
        private final double endAngle;
        private long startTimeMs = -1;

        CardAnimation(CardPayload card, boolean faceUp, double startX, double startY,
                      double endX, double endY, double startAngle, double endAngle) {
            this.card = card;
            this.faceUp = faceUp;
            this.startX = startX;
            this.startY = startY;
            this.endX = endX;
            this.endY = endY;
            this.startAngle = startAngle;
            this.endAngle = endAngle;
        }

        void start() {
            startTimeMs = System.currentTimeMillis();
        }

        boolean isDone() {
            return startTimeMs >= 0 && progress() >= 1.0;
        }

        double currentX() {
            return lerp(startX, endX, ease());
        }

        double currentY() {
            return lerp(startY, endY, ease());
        }

        double currentAngle() {
            return lerp(startAngle, endAngle, ease());
        }

        void draw(Graphics2D g2, int x, int y, int width, int height) {
            if (faceUp && card != null) {
                card.toCard().drawFront(g2, x, y, width, height);
            } else {
                Card.drawBackImage(g2, x, y, width, height);
            }
        }

        private double progress() {
            if (startTimeMs < 0) {
                return 0.0;
            }
            return Math.min(1.0, (double) (System.currentTimeMillis() - startTimeMs) / ANIMATION_DURATION_MS);
        }

        private double ease() {
            double t = progress();
            return t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2.0;
        }

        private static double lerp(double start, double end, double amount) {
            return start + (end - start) * amount;
        }
    }

    private record CardPlacement(int handIndex, CardPayload card, int x, int y,
                                 double angleRadians, double rotationPivotX,
                                 double rotationPivotY, Shape hitShape) {
    }

    private class TableMouseHandler extends MouseAdapter {
        @Override
        public void mouseClicked(MouseEvent e) {
            handleMouseClick(e.getPoint());
        }
    }

    private class TableMouseMotionHandler extends MouseMotionAdapter {
        @Override
        public void mouseMoved(MouseEvent e) {
            updateCursor(e.getPoint());
        }
    }
}
